export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const alive = new Set(cells.map(([x, y]) => key(x, y)));
  const neighbourCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighbourCounts.set(k, (neighbourCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighbourCounts) {
    const [xs, ys] = k.split(",");
    const x = Number(xs);
    const y = Number(ys);
    if (alive.has(k)) {
      if (count === 2 || count === 3) result.push([x, y]);
    } else {
      if (count === 3) result.push([x, y]);
    }
  }
  for (const [x, y] of cells) {
    if (!neighbourCounts.has(key(x, y))) {
      // live cell with 0 neighbours dies anyway, no action needed
    }
  }

  return result;
}

